FUNCTION LinearSearch(arr[1...n], target)
  FOR i ← 1 TO n DO
    IF arr[i] = target THEN
      RETURN i  // Found at position i
    END IF
  END FOR
  RETURN -1  // Not found
END FUNCTION

// Analysis:
// Best case: O(1) - element found at first position
// Worst case: O(n) - element not found or at last position
// Average case: O(n) - (n+1)/2 comparisons on average

#include <stdio.h>

void tripleNested(int n) {
    int count = 0;
    // i loop: n times
    for (int i = 0; i < n; i++) {
        // j loop: n times for each i
        for (int j = 0; j < n; j++) {
            // k loop: n times for each j
            for (int k = 0; k < n; k++) {
                count++;  // This executes n³ times
            }
        }
    }
    printf("Total operations: %d\n", count);
}

// Analysis:
// Outer loop: n iterations
// Middle loop: n iterations per outer iteration
// Inner loop: n iterations per middle iteration
// Total: n × n × n = n³ operations
// Time Complexity: O(n³)
// Space Complexity: O(1) - only counter variable
